script.text:
      /* <flatten type="Javascript"> */
function active$ShiftScheduleFilter(f) { f.add_onResponseComplete(on$ShiftScheduleFilter$ResponseComplete); }
function close$ShiftScheduleFilter(f) {try {f.remove_onResponseComplete(on$ShiftScheduleFilter$ResponseComplete);} catch (ex) {}}
function onchange$ShiftScheduleFilter$Deparment(o) {o.parentForm.request('Reference', 'Reference', ['ma_bp']);}
function on$ShiftScheduleFilter$ResponseComplete(f, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Reference':
      f.setItemControlBehavior('bp_ref', result[0].Value, true);
      f.setReferenceKeyFilter('ma_nv');
      break;
    case 'Checking':
      var id = f.get_id(), v = f._language == 'v', ms = f.getItem('tu_ngay').field.Label
      var e1 = (v ? 'Trường <span class="Highlight">' + ms + '</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">' + ms + '</span> must not be blank or has invalid value.');
      var diffDate = dateDiffInDays(f.getItemValue('tu_ngay', null, null, true), f.getItemValue('den_ngay', null, null, true));
      if (diffDate < 0 || diffDate >= 36) {
        $func.hideWait(id);
        $message.show(e1, String.format('$find(\'{0}\').getItem(\'tu_ngay\').focus()', id));
        f._checked = false;
        break;
      }
      g._refreshMemvars = true;
      g._dateFrom = f.getItem('tu_ngay').value;
      g._dateTo = f.getItem('den_ngay').value;
      g._dept = f.getItemValue('ma_bp');
      g._staff = f.getItemValue('ma_nv');
      g._pos = f.getItemValue('ma_vtr');
      g._grade = f.getItemValue('bac_ql');
      g._deptRef = f.getItemValue('bp_ref');
      g._deptName = f.getItemValue('ten_bp%l');
      g._alterTitle = [null, [['%d1', g._dateFrom, true], ['%d2', g._dateTo, true], ['%s1', g._deptName, true]]];
      if (!g._day) g._day = ((g._dateFrom.toString()) + (String.fromCharCode(253)) + (g._dateTo.toString()));
      break;
    default:
      break;
  }
}
function dateDiffInDays(d1, d2) {
  var u1 = Date.UTC(d1.getFullYear(), d1.getMonth(), d1.getDate()), u2 = Date.UTC(d2.getFullYear(), d2.getMonth(), d2.getDate());
  return Math.floor((u2 - u1) / 86400000);
}
function remove$GridReport$Filter(g) {
  var r = (g._showFields + ',' + g._hiddenFields).split(','), name, field;
  if (g._day != ((g._dateFrom.toString()) + (String.fromCharCode(253)) + (g._dateTo.toString()))) {
    for (i = 0; i < r.length; i++) {
      for (var j = 0; j < g._filter.length; j++) {
        name = $func.trim(r[i]);
        field = $func.findField(name, g._fields)
        if (field) field.FilterPanelValue = '';
        if (g._filter[j].match(/^(\w+):/)[1] == name) {
          Array.removeAt(g._filter, j);
          break;
        }
      }
    }
    g._day = ((g._dateFrom.toString()) + (String.fromCharCode(253)) + (g._dateTo.toString()));
  }
}
/* </flatten> */
